import React from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  const luxuryTerracotta = '#A65D46'; // The muted, expensive clay color

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif', color: '#fff' }}>
      
      {/* 1. CLEAN NAV (LOGO TOP LEFT) */}
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        padding: '20px 40px', 
        backgroundColor: '#000', 
        borderBottom: '1px solid #1a1a1a'
      }}>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
          <img src={Logo} alt="Àmí by T" style={{ height: '65px', filter: 'brightness(1.2)' }} />
          <span style={{ fontSize: '0.6rem', letterSpacing: '2px', color: '#666', marginTop: '5px' }}>TASTE AND STYLE</span>
        </div>

        <div style={{ display: 'flex', gap: '30px' }}>
          {['Home', 'Small Chops', 'Office Lunch', 'About Us'].map((item) => (
            <a key={item} href={`#${item.toLowerCase().replace(' ', '')}`} style={{ color: '#fff', textDecoration: 'none', fontSize: '0.85rem', opacity: 0.8 }}>{item}</a>
          ))}
        </div>

        <div style={{ border: `1px solid ${luxuryTerracotta}`, color: luxuryTerracotta, padding: '8px 20px', borderRadius: '20px', fontSize: '0.75rem' }}>
          3 items
        </div>
      </nav>

      {/* 2. THE MAIN SECTION */}
      <main style={{ padding: '40px 40px' }}>
        
        {/* SECTION HEADER (AS PER YOUR IMAGE) */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '30px' }}>
           <h2 style={{ fontSize: '2.2rem', fontWeight: '400', margin: 0 }}>Featured Categories</h2>
           <span style={{ color: luxuryTerracotta, fontSize: '0.8rem', borderBottom: `1px solid ${luxuryTerracotta}`, cursor: 'pointer' }}>Show All ›</span>
        </div>

        {/* THE GRID CONTAINER (THIS MOVES EVERYTHING UP) */}
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', 
          gap: '25px'
        }}>
          
          {/* CATEGORY CARD 1: SMALL CHOPS */}
          <div style={{ 
            backgroundColor: '#111', 
            borderRadius: '12px', 
            padding: '30px', 
            border: '1px solid #1a1a1a' 
          }}>
            <h3 style={{ textAlign: 'center', color: luxuryTerracotta, fontSize: '1.5rem', marginBottom: '25px', fontWeight: '300' }}>
              The Àmí Starter Pack (24 pcs)
            </h3>
            <Menu /> {/* This will now render inside the card */}
          </div>

          {/* CATEGORY CARD 2: LUNCH (OR WIGS AS SEEN IN YOUR IMAGE) */}
          <div style={{ 
            backgroundColor: '#111', 
            borderRadius: '12px', 
            padding: '30px', 
            border: '1px solid #1a1a1a' 
          }}>
             <h3 style={{ textAlign: 'center', color: luxuryTerracotta, fontSize: '1.5rem', marginBottom: '25px', fontWeight: '300' }}>
              Office Lunch Subscriptions
            </h3>
            <Lunch />
          </div>

        </div>
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '60px', color: '#333', fontSize: '0.7rem' }}>
        <p>© 2026 ÀMÍ BY T | LAGOS</p>
      </footer>

    </div>
  );
}

export default App;
